custom_css:
.print-format-preview {
	margin-top: 12px;
}
.letter-head {
	border-radius: 18px;
	background: #f8f8f8;
	padding: 12px;
	margin-left: 12px;
	margin-right: 12px;
}
.letterhead-container {
	width: 100%;
}
.letterhead-container .other-details {
	position: absolute;
	right: 0;
	bottom: 0;
}
.logo-address {
	width: 65%;
	vertical-align: top;
}

.letter-head .logo {
	width: 90px;
	display: block;
	margin-bottom: 10px;
}

.letter-head .logo img {
	border-radius: 15px;
}

.company-name {
	color: #171717;
	font-weight: bold;
	line-height: 23px;
	margin-bottom: 5px;
}

.company-address {
	color: #171717;
	width: 300px;
}

.invoice-title {
	font-weight: bold;
}

.invoice-number {
	color: #7c7c7c;
}

.contact-title {
	color: #7c7c7c;
	width: 60px;
	display: inline-block;
	vertical-align: top;
	margin-right: 10px;
}

.contact-value {
	color: #171717;
	display: inline-block;
}
.letterhead-container td {
	padding: 0px !important;
	position: relative;
}
